import React, {useState} from "react";
import classes from './ProfileInfo.module.css';
import Preloader from "../../Common/Preloader/Preloader";

import ProfileStatusWithHooks from "./ProfileStatusWithHooks";
import userDefaultPhoto from "../../img/user.png";
import ProfileDataForm from "./ProfileDataForm";
import Preloader2 from "../../Common/Preloader/Preloader2";
import Profile from "../Profile";
import topImage from '../../img/topImage.jpg'
import {updateUserStatus} from "../../../redux/profile-reducer";
import youtube from '../../img/youtube.png';
import vk from '../../img/vk.svg';
import twitter from '../../img/twitter.png';
import instagram from '../../img/instagram.svg';
import github from '../../img/github.svg';
import facebook from '../../img/facebook.png';
import web from '../../img/globe.svg';
import mainLink from '../../img/link.svg';






const ProfileInfo = ({
                         profile,
                         status,
                         updateUserStatus,
                         isOwner,
                         savePhoto,
                         saveProfile,
                         isPhotoSaving
                     }) => {
    //Т.К. изначально в редьюсере профайл null
    //то пишем условие !props.profile - если в пропсе ничего нет
    //это аналог (props.profile==null || props.profile)
    //если пропсы равны нулл или (||-это или андефайдет)
    //! - это отрицание
    let [editMode, setEditMode] = useState(false);


    if (!profile) {
        return <Preloader2/>
    }
    const onMainPhotoSelected = (e) => {
        if (e.target.files.length) {
            savePhoto(e.target.files[0])
        }
    }

    const onSubmit = (formData) => {
        saveProfile(formData).then(() => {
            setEditMode(false);
        });
    }

    return <div className={classes.content}>
        {isOwner && <input className={classes.file} type={'file'} onChange={onMainPhotoSelected}/>}
        <div className={classes.topImageblock}>
            <img className={classes.topImage} src={topImage}
                 alt='Верхний баннер профиля'/>
        </div>
        {editMode
            ? <ProfileDataForm initialValues={profile} profile={profile} onSubmit={onSubmit}/>
            : <ProfileData profile={profile} isOwner={isOwner} status={status} updateUserStatus={updateUserStatus}
                           goToEditMode={() => {
                               setEditMode(true)
                           }}/>}
    </div>
}

const ProfileData = ({profile, isOwner, goToEditMode, status, updateUserStatus}) => {
    return <div>

        <div className={classes.profiletext}>
            <div className={classes.fullName}><b>{profile.fullName}</b></div>
            <div className={classes.status}>
                <ProfileStatusWithHooks status={status} updateUserStatus={updateUserStatus}/>
            </div>

            <div className={classes.aboutMe}>
                <b>About me</b>
                <div>{profile.aboutMe}</div>
                <div className={classes.job}>
                    <b> Looking for a job:</b>
                    <span>
                        {profile.lookingForAJob
                            ? " Yes"
                            : " No"}
                    </span>
                </div>
                <div className={classes.job}>
                    <b>My skills: </b>
                    <span>
                    {profile.lookingForAJobDescription}
                </span>
                </div>
            </div>
            <div>
                <b>Contacts</b>: {Object.keys(profile.contacts).map(key => {
                return <Contact key={key} contactTitle={key} contactValue={profile.contacts[key]}/>
            })}
            </div>

            <div className={classes.mainlinks_wrapper}>
                <div className={classes.firstlinks_wrapper}>
                    <div className={classes.links_wrapper}>
                        <a target="_blank" className={classes.links} href={profile.contacts.youtube ? profile.contacts.youtube : "https://youtube.com/"}>
                            <img className={classes.links} src={youtube} />
                        </a>
                    </div>
                    <div className={classes.links_wrapper}>
                        <a target="_blank" className={classes.links} href={profile.contacts.vk ? profile.contacts.vk : "https://vk.com/"}>
                            <img className={classes.links} src={vk} />
                        </a>
                    </div>
                    <div className={classes.links_wrapper}>
                        <a target="_blank" className={classes.links} href={profile.contacts.twitter ? profile.contacts.twitter : "https://twitter.com/"}>
                            <img className={classes.links} src={twitter} />
                        </a>
                    </div>
                    <div className={classes.links_wrapper}>
                        <a target="_blank" className={classes.links} href={profile.contacts.instagram ? profile.contacts.instagram : "https://instagram.com/"}>
                            <img className={classes.links} src={instagram} />
                        </a>
                    </div>
                </div>
                <div className={classes.secondlinks_wrapper}>
                    <div className={classes.links_wrapper}>
                        <a target="_blank" className={classes.links} href={profile.contacts.github ? profile.contacts.github : "https://github.com/"}>
                            <img className={classes.links} src={github} />
                        </a>
                    </div>
                    <div className={classes.links_wrapper}>
                        <a target="_blank" className={classes.links} href={profile.contacts.facebook ? profile.contacts.facebook : "https://facebook.com/"}>
                            <img className={classes.links} src={facebook} />
                        </a>
                    </div>
                    <div className={classes.links_wrapper}>
                        <a target="_blank" className={classes.links} href={profile.contacts.website ? profile.contacts.website : "https://website.com/"}>
                            <img className={classes.links} src={web} />
                        </a>
                    </div>
                    <div className={classes.links_wrapper}>
                        <a target="_blank" className={classes.links} href={profile.contacts.mainLink ? profile.contacts.mainLink : "https://mainLink.com/"}>
                            <img className={classes.links} src={mainLink} />
                        </a>
                    </div>
                </div>
            </div>


            {isOwner && <div>
                <button onClick={goToEditMode}>Edit</button>
            </div>}
        </div>
    </div>

}


const Contact = ({contactTitle, contactValue}) => {
    return <div><b>{contactTitle}</b>:{contactValue} </div>
}

export default ProfileInfo;

/*{условие (да или нет) ? значение 1 (да) : значение 2 (нет)}*/

